export class IndexedAttestation {
  public attestingIndices: Array<bigint> = [];
  public data: AttestationData = new AttestationData();
  public signature: Bytes96 = new Bytes96();

  sszBytesLen(): number {
    let size = 228;
    size += this.attestingIndices.length * 8;
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Offset placeholder for 'attesting_indices'
    const offsetPos0 = offset;
    offset += 4;
    // Field 'data'
    offset = this.data.sszAppend(buf, offset);
    // Field 'signature'
    offset = this.signature.sszAppend(buf, offset);

    // Dynamic field 'attesting_indices'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    for (const v of this.attestingIndices) {
      dv.setBigUint64(offset, v, true); offset += 8;
    }
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): IndexedAttestation {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 228) {
      throw new SszError('buffer too small');
    }
    const t = new IndexedAttestation();
    const offset0 = dv.getUint32(0, true);
    if (offset0 !== 228) {
      throw new SszError('invalid offset');
    }
    t.data = AttestationData.fromSszBytes(buf.subarray(4, 132));
    t.signature = Bytes96.fromSszBytes(buf.subarray(132, 228));

    {
      const dynBuf = buf.subarray(offset0, buf.length);
      {
        const dynDv = new DataView(dynBuf.buffer, dynBuf.byteOffset, dynBuf.byteLength);
        const count = Math.floor(dynBuf.length / 8);
        t.attestingIndices = new Array<bigint>(count);
        for (let i = 0; i < count; i++) {
          t.attestingIndices[i] = dynDv.getBigUint64(i * 8, true);
        }
      }
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'attesting_indices'
    {
      const subIdx = h.index();
      for (const v of this.attestingIndices) {
        h.appendUint64(v);
      }
      h.fillUpTo32();
      h.merkleizeWithMixin(subIdx, this.attestingIndices.length, 512);
    }

    // Field 'data'
    this.data.treeHashWith(h);

    // Field 'signature'
    this.signature.treeHashWith(h);

    h.merkleize(idx);
  }
}

export class AttesterSlashing {
  public attestation1: IndexedAttestation = new IndexedAttestation();
  public attestation2: IndexedAttestation = new IndexedAttestation();

  sszBytesLen(): number {
    let size = 8;
    size += this.attestation1.sszBytesLen();
    size += this.attestation2.sszBytesLen();
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Offset placeholder for 'attestation_1'
    const offsetPos0 = offset;
    offset += 4;
    // Offset placeholder for 'attestation_2'
    const offsetPos1 = offset;
    offset += 4;

    // Dynamic field 'attestation_1'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    offset = this.attestation1.sszAppend(buf, offset);
    // Dynamic field 'attestation_2'
    dv.setUint32(offsetPos1, offset - startOffset, true);
    offset = this.attestation2.sszAppend(buf, offset);
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): AttesterSlashing {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 8) {
      throw new SszError('buffer too small');
    }
    const t = new AttesterSlashing();
    const offset0 = dv.getUint32(0, true);
    if (offset0 !== 8) {
      throw new SszError('invalid offset');
    }
    const offset1 = dv.getUint32(4, true);
    if (offset1 < offset0 || offset1 > buf.length) {
      throw new SszError('invalid offset');
    }

    {
      const dynBuf = buf.subarray(offset0, offset1);
      t.attestation1 = IndexedAttestation.fromSszBytes(dynBuf);
    }
    {
      const dynBuf = buf.subarray(offset1, buf.length);
      t.attestation2 = IndexedAttestation.fromSszBytes(dynBuf);
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'attestation_1'
    this.attestation1.treeHashWith(h);

    // Field 'attestation_2'
    this.attestation2.treeHashWith(h);

    h.merkleize(idx);
  }
}

export class Attestation {
  public aggregationBits: Uint8Array = new Uint8Array(0);
  public data: AttestationData = new AttestationData();
  public signature: Bytes96 = new Bytes96();

  sszBytesLen(): number {
    let size = 228;
    size += this.aggregationBits.length;
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Offset placeholder for 'aggregation_bits'
    const offsetPos0 = offset;
    offset += 4;
    // Field 'data'
    offset = this.data.sszAppend(buf, offset);
    // Field 'signature'
    offset = this.signature.sszAppend(buf, offset);

    // Dynamic field 'aggregation_bits'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    buf.set(this.aggregationBits, offset); offset += this.aggregationBits.length;
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): Attestation {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 228) {
      throw new SszError('buffer too small');
    }
    const t = new Attestation();
    const offset0 = dv.getUint32(0, true);
    if (offset0 !== 228) {
      throw new SszError('invalid offset');
    }
    t.data = AttestationData.fromSszBytes(buf.subarray(4, 132));
    t.signature = Bytes96.fromSszBytes(buf.subarray(132, 228));

    {
      const dynBuf = buf.subarray(offset0, buf.length);
      t.aggregationBits = dynBuf.slice();
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'aggregation_bits'
    h.putBitlist(this.aggregationBits, 2048);

    // Field 'data'
    this.data.treeHashWith(h);

    // Field 'signature'
    this.signature.treeHashWith(h);

    h.merkleize(idx);
  }
}

export class ExecutionPayload {
  public parentHash: Bytes32 = new Bytes32();
  public feeRecipient: Bytes20 = new Bytes20();
  public stateRoot: Bytes32 = new Bytes32();
  public receiptsRoot: Bytes32 = new Bytes32();
  public logsBloom: Bytes256 = new Bytes256();
  public prevRandao: Bytes32 = new Bytes32();
  public blockNumber: bigint = 0n;
  public gasLimit: bigint = 0n;
  public gasUsed: bigint = 0n;
  public timestamp: bigint = 0n;
  public extraData: Uint8Array = new Uint8Array(0);
  public baseFeePerGas: Bytes32 = new Bytes32();
  public blockHash: Bytes32 = new Bytes32();
  public transactions: Array<Uint8Array> = [];
  public withdrawals: Array<Withdrawal> = [];
  public blobGasUsed: bigint = 0n;
  public excessBlobGas: bigint = 0n;

  sszBytesLen(): number {
    let size = 528;
    size += this.extraData.length * 1;
    size += this.transactions.length * 4;
    for (const item of this.transactions) {
      size += item.length;
    }
    size += this.withdrawals.length * 44;
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Field 'parent_hash'
    offset = this.parentHash.sszAppend(buf, offset);
    // Field 'fee_recipient'
    offset = this.feeRecipient.sszAppend(buf, offset);
    // Field 'state_root'
    offset = this.stateRoot.sszAppend(buf, offset);
    // Field 'receipts_root'
    offset = this.receiptsRoot.sszAppend(buf, offset);
    // Field 'logs_bloom'
    offset = this.logsBloom.sszAppend(buf, offset);
    // Field 'prev_randao'
    offset = this.prevRandao.sszAppend(buf, offset);
    // Field 'block_number'
    dv.setBigUint64(offset, this.blockNumber, true); offset += 8;
    // Field 'gas_limit'
    dv.setBigUint64(offset, this.gasLimit, true); offset += 8;
    // Field 'gas_used'
    dv.setBigUint64(offset, this.gasUsed, true); offset += 8;
    // Field 'timestamp'
    dv.setBigUint64(offset, this.timestamp, true); offset += 8;
    // Offset placeholder for 'extra_data'
    const offsetPos0 = offset;
    offset += 4;
    // Field 'base_fee_per_gas'
    offset = this.baseFeePerGas.sszAppend(buf, offset);
    // Field 'block_hash'
    offset = this.blockHash.sszAppend(buf, offset);
    // Offset placeholder for 'transactions'
    const offsetPos1 = offset;
    offset += 4;
    // Offset placeholder for 'withdrawals'
    const offsetPos2 = offset;
    offset += 4;
    // Field 'blob_gas_used'
    dv.setBigUint64(offset, this.blobGasUsed, true); offset += 8;
    // Field 'excess_blob_gas'
    dv.setBigUint64(offset, this.excessBlobGas, true); offset += 8;

    // Dynamic field 'extra_data'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    buf.set(this.extraData, offset); offset += this.extraData.length;
    // Dynamic field 'transactions'
    dv.setUint32(offsetPos1, offset - startOffset, true);
    {
      const listStart = offset;
      for (let i = 0; i < this.transactions.length; i++) {
        offset += 4;
      }
      for (let i = 0; i < this.transactions.length; i++) {
        dv.setUint32(listStart + i * 4, offset - listStart, true);
        buf.set(this.transactions[i], offset);
        offset += this.transactions[i].length;
      }
    }
    // Dynamic field 'withdrawals'
    dv.setUint32(offsetPos2, offset - startOffset, true);
    for (const item of this.withdrawals) {
      offset = item.sszAppend(buf, offset);
    }
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): ExecutionPayload {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 528) {
      throw new SszError('buffer too small');
    }
    const t = new ExecutionPayload();
    t.parentHash = Bytes32.fromSszBytes(buf.subarray(0, 32));
    t.feeRecipient = Bytes20.fromSszBytes(buf.subarray(32, 52));
    t.stateRoot = Bytes32.fromSszBytes(buf.subarray(52, 84));
    t.receiptsRoot = Bytes32.fromSszBytes(buf.subarray(84, 116));
    t.logsBloom = Bytes256.fromSszBytes(buf.subarray(116, 372));
    t.prevRandao = Bytes32.fromSszBytes(buf.subarray(372, 404));
    t.blockNumber = dv.getBigUint64(404, true);
    t.gasLimit = dv.getBigUint64(412, true);
    t.gasUsed = dv.getBigUint64(420, true);
    t.timestamp = dv.getBigUint64(428, true);
    const offset0 = dv.getUint32(436, true);
    if (offset0 !== 528) {
      throw new SszError('invalid offset');
    }
    t.baseFeePerGas = Bytes32.fromSszBytes(buf.subarray(440, 472));
    t.blockHash = Bytes32.fromSszBytes(buf.subarray(472, 504));
    const offset1 = dv.getUint32(504, true);
    if (offset1 < offset0 || offset1 > buf.length) {
      throw new SszError('invalid offset');
    }
    const offset2 = dv.getUint32(508, true);
    if (offset2 < offset1 || offset2 > buf.length) {
      throw new SszError('invalid offset');
    }
    t.blobGasUsed = dv.getBigUint64(512, true);
    t.excessBlobGas = dv.getBigUint64(520, true);

    {
      const dynBuf = buf.subarray(offset0, offset1);
      t.extraData = dynBuf.slice();
    }
    {
      const dynBuf = buf.subarray(offset1, offset2);
      if (dynBuf.length > 0) {
        const dynDv = new DataView(dynBuf.buffer, dynBuf.byteOffset, dynBuf.byteLength);
        const firstOff = dynDv.getUint32(0, true);
        if (firstOff % 4 !== 0) {
          throw new SszError('invalid offset');
        }
        const count = firstOff / 4;
        t.transactions = new Array<Uint8Array>(count);
        for (let i = 0; i < count; i++) {
          const start = dynDv.getUint32(i * 4, true);
          const end = i + 1 < count ? dynDv.getUint32((i + 1) * 4, true) : dynBuf.length;
          if (start > end || end > dynBuf.length) {
            throw new SszError('invalid offset');
          }
          t.transactions[i] = dynBuf.slice(start, end);
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset2, buf.length);
      {
        const count = Math.floor(dynBuf.length / 44);
        t.withdrawals = new Array<Withdrawal>(count);
        for (let i = 0; i < count; i++) {
          const off = i * 44;
          t.withdrawals[i] = Withdrawal.fromSszBytes(dynBuf.subarray(off, off + 44));
        }
      }
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'parent_hash'
    this.parentHash.treeHashWith(h);

    // Field 'fee_recipient'
    this.feeRecipient.treeHashWith(h);

    // Field 'state_root'
    this.stateRoot.treeHashWith(h);

    // Field 'receipts_root'
    this.receiptsRoot.treeHashWith(h);

    // Field 'logs_bloom'
    this.logsBloom.treeHashWith(h);

    // Field 'prev_randao'
    this.prevRandao.treeHashWith(h);

    // Field 'block_number'
    h.putUint64(this.blockNumber);

    // Field 'gas_limit'
    h.putUint64(this.gasLimit);

    // Field 'gas_used'
    h.putUint64(this.gasUsed);

    // Field 'timestamp'
    h.putUint64(this.timestamp);

    // Field 'extra_data'
    {
      const subIdx = h.index();
      h.appendBytes32(this.extraData);
      h.merkleizeWithMixin(subIdx, this.extraData.length, 1);
    }

    // Field 'base_fee_per_gas'
    this.baseFeePerGas.treeHashWith(h);

    // Field 'block_hash'
    this.blockHash.treeHashWith(h);

    // Field 'transactions'
    {
      const subIdx = h.index();
      for (const item of this.transactions) {
        const inner = h.index();
        h.appendBytes32(item);
        h.merkleizeWithMixin(inner, item.length, 33554432);
      }
      h.merkleizeWithMixin(subIdx, this.transactions.length, 1048576);
    }

    // Field 'withdrawals'
    {
      const subIdx = h.index();
      for (const item of this.withdrawals) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.withdrawals.length, 16);
    }

    // Field 'blob_gas_used'
    h.putUint64(this.blobGasUsed);

    // Field 'excess_blob_gas'
    h.putUint64(this.excessBlobGas);

    h.merkleize(idx);
  }
}

export class BeaconBlockBody {
  public randaoReveal: Bytes96 = new Bytes96();
  public eth1Data: ETH1Data = new ETH1Data();
  public graffiti: Bytes32 = new Bytes32();
  public proposerSlashings: Array<ProposerSlashing> = [];
  public attesterSlashings: Array<AttesterSlashing> = [];
  public attestations: Array<Attestation> = [];
  public deposits: Array<Deposit> = [];
  public voluntaryExits: Array<SignedVoluntaryExit> = [];
  public syncAggregate: SyncAggregate = new SyncAggregate();
  public executionPayload: ExecutionPayload = new ExecutionPayload();
  public blsToExecutionChanges: Array<SignedBLSToExecutionChange> = [];
  public blobKzgCommitments: Array<KZGCommitment> = [];

  sszBytesLen(): number {
    let size = 392;
    size += this.proposerSlashings.length * 416;
    size += this.attesterSlashings.length * 4;
    for (const item of this.attesterSlashings) {
      size += item.sszBytesLen();
    }
    size += this.attestations.length * 4;
    for (const item of this.attestations) {
      size += item.sszBytesLen();
    }
    size += this.deposits.length * 1240;
    size += this.voluntaryExits.length * 112;
    size += this.executionPayload.sszBytesLen();
    size += this.blsToExecutionChanges.length * 172;
    size += this.blobKzgCommitments.length * 48;
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Field 'randao_reveal'
    offset = this.randaoReveal.sszAppend(buf, offset);
    // Field 'eth1_data'
    offset = this.eth1Data.sszAppend(buf, offset);
    // Field 'graffiti'
    offset = this.graffiti.sszAppend(buf, offset);
    // Offset placeholder for 'proposer_slashings'
    const offsetPos0 = offset;
    offset += 4;
    // Offset placeholder for 'attester_slashings'
    const offsetPos1 = offset;
    offset += 4;
    // Offset placeholder for 'attestations'
    const offsetPos2 = offset;
    offset += 4;
    // Offset placeholder for 'deposits'
    const offsetPos3 = offset;
    offset += 4;
    // Offset placeholder for 'voluntary_exits'
    const offsetPos4 = offset;
    offset += 4;
    // Field 'sync_aggregate'
    offset = this.syncAggregate.sszAppend(buf, offset);
    // Offset placeholder for 'execution_payload'
    const offsetPos5 = offset;
    offset += 4;
    // Offset placeholder for 'bls_to_execution_changes'
    const offsetPos6 = offset;
    offset += 4;
    // Offset placeholder for 'blob_kzg_commitments'
    const offsetPos7 = offset;
    offset += 4;

    // Dynamic field 'proposer_slashings'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    for (const item of this.proposerSlashings) {
      offset = item.sszAppend(buf, offset);
    }
    // Dynamic field 'attester_slashings'
    dv.setUint32(offsetPos1, offset - startOffset, true);
    {
      const listStart = offset;
      for (let i = 0; i < this.attesterSlashings.length; i++) {
        offset += 4;
      }
      for (let i = 0; i < this.attesterSlashings.length; i++) {
        dv.setUint32(listStart + i * 4, offset - listStart, true);
        offset = this.attesterSlashings[i].sszAppend(buf, offset);
      }
    }
    // Dynamic field 'attestations'
    dv.setUint32(offsetPos2, offset - startOffset, true);
    {
      const listStart = offset;
      for (let i = 0; i < this.attestations.length; i++) {
        offset += 4;
      }
      for (let i = 0; i < this.attestations.length; i++) {
        dv.setUint32(listStart + i * 4, offset - listStart, true);
        offset = this.attestations[i].sszAppend(buf, offset);
      }
    }
    // Dynamic field 'deposits'
    dv.setUint32(offsetPos3, offset - startOffset, true);
    for (const item of this.deposits) {
      offset = item.sszAppend(buf, offset);
    }
    // Dynamic field 'voluntary_exits'
    dv.setUint32(offsetPos4, offset - startOffset, true);
    for (const item of this.voluntaryExits) {
      offset = item.sszAppend(buf, offset);
    }
    // Dynamic field 'execution_payload'
    dv.setUint32(offsetPos5, offset - startOffset, true);
    offset = this.executionPayload.sszAppend(buf, offset);
    // Dynamic field 'bls_to_execution_changes'
    dv.setUint32(offsetPos6, offset - startOffset, true);
    for (const item of this.blsToExecutionChanges) {
      offset = item.sszAppend(buf, offset);
    }
    // Dynamic field 'blob_kzg_commitments'
    dv.setUint32(offsetPos7, offset - startOffset, true);
    for (const item of this.blobKzgCommitments) {
      offset = item.sszAppend(buf, offset);
    }
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): BeaconBlockBody {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 392) {
      throw new SszError('buffer too small');
    }
    const t = new BeaconBlockBody();
    t.randaoReveal = Bytes96.fromSszBytes(buf.subarray(0, 96));
    t.eth1Data = ETH1Data.fromSszBytes(buf.subarray(96, 168));
    t.graffiti = Bytes32.fromSszBytes(buf.subarray(168, 200));
    const offset0 = dv.getUint32(200, true);
    if (offset0 !== 392) {
      throw new SszError('invalid offset');
    }
    const offset1 = dv.getUint32(204, true);
    if (offset1 < offset0 || offset1 > buf.length) {
      throw new SszError('invalid offset');
    }
    const offset2 = dv.getUint32(208, true);
    if (offset2 < offset1 || offset2 > buf.length) {
      throw new SszError('invalid offset');
    }
    const offset3 = dv.getUint32(212, true);
    if (offset3 < offset2 || offset3 > buf.length) {
      throw new SszError('invalid offset');
    }
    const offset4 = dv.getUint32(216, true);
    if (offset4 < offset3 || offset4 > buf.length) {
      throw new SszError('invalid offset');
    }
    t.syncAggregate = SyncAggregate.fromSszBytes(buf.subarray(220, 380));
    const offset5 = dv.getUint32(380, true);
    if (offset5 < offset4 || offset5 > buf.length) {
      throw new SszError('invalid offset');
    }
    const offset6 = dv.getUint32(384, true);
    if (offset6 < offset5 || offset6 > buf.length) {
      throw new SszError('invalid offset');
    }
    const offset7 = dv.getUint32(388, true);
    if (offset7 < offset6 || offset7 > buf.length) {
      throw new SszError('invalid offset');
    }

    {
      const dynBuf = buf.subarray(offset0, offset1);
      {
        const count = Math.floor(dynBuf.length / 416);
        t.proposerSlashings = new Array<ProposerSlashing>(count);
        for (let i = 0; i < count; i++) {
          const off = i * 416;
          t.proposerSlashings[i] = ProposerSlashing.fromSszBytes(dynBuf.subarray(off, off + 416));
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset1, offset2);
      if (dynBuf.length > 0) {
        const dynDv = new DataView(dynBuf.buffer, dynBuf.byteOffset, dynBuf.byteLength);
        const firstOff = dynDv.getUint32(0, true);
        if (firstOff % 4 !== 0) {
          throw new SszError('invalid offset');
        }
        const count = firstOff / 4;
        t.attesterSlashings = new Array<AttesterSlashing>(count);
        for (let i = 0; i < count; i++) {
          const start = dynDv.getUint32(i * 4, true);
          const end = i + 1 < count ? dynDv.getUint32((i + 1) * 4, true) : dynBuf.length;
          if (start > end || end > dynBuf.length) {
            throw new SszError('invalid offset');
          }
          t.attesterSlashings[i] = AttesterSlashing.fromSszBytes(dynBuf.subarray(start, end));
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset2, offset3);
      if (dynBuf.length > 0) {
        const dynDv = new DataView(dynBuf.buffer, dynBuf.byteOffset, dynBuf.byteLength);
        const firstOff = dynDv.getUint32(0, true);
        if (firstOff % 4 !== 0) {
          throw new SszError('invalid offset');
        }
        const count = firstOff / 4;
        t.attestations = new Array<Attestation>(count);
        for (let i = 0; i < count; i++) {
          const start = dynDv.getUint32(i * 4, true);
          const end = i + 1 < count ? dynDv.getUint32((i + 1) * 4, true) : dynBuf.length;
          if (start > end || end > dynBuf.length) {
            throw new SszError('invalid offset');
          }
          t.attestations[i] = Attestation.fromSszBytes(dynBuf.subarray(start, end));
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset3, offset4);
      {
        const count = Math.floor(dynBuf.length / 1240);
        t.deposits = new Array<Deposit>(count);
        for (let i = 0; i < count; i++) {
          const off = i * 1240;
          t.deposits[i] = Deposit.fromSszBytes(dynBuf.subarray(off, off + 1240));
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset4, offset5);
      {
        const count = Math.floor(dynBuf.length / 112);
        t.voluntaryExits = new Array<SignedVoluntaryExit>(count);
        for (let i = 0; i < count; i++) {
          const off = i * 112;
          t.voluntaryExits[i] = SignedVoluntaryExit.fromSszBytes(dynBuf.subarray(off, off + 112));
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset5, offset6);
      t.executionPayload = ExecutionPayload.fromSszBytes(dynBuf);
    }
    {
      const dynBuf = buf.subarray(offset6, offset7);
      {
        const count = Math.floor(dynBuf.length / 172);
        t.blsToExecutionChanges = new Array<SignedBLSToExecutionChange>(count);
        for (let i = 0; i < count; i++) {
          const off = i * 172;
          t.blsToExecutionChanges[i] = SignedBLSToExecutionChange.fromSszBytes(dynBuf.subarray(off, off + 172));
        }
      }
    }
    {
      const dynBuf = buf.subarray(offset7, buf.length);
      {
        const count = Math.floor(dynBuf.length / 48);
        t.blobKzgCommitments = new Array<KZGCommitment>(count);
        for (let i = 0; i < count; i++) {
          const off = i * 48;
          t.blobKzgCommitments[i] = KZGCommitment.fromSszBytes(dynBuf.subarray(off, off + 48));
        }
      }
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'randao_reveal'
    this.randaoReveal.treeHashWith(h);

    // Field 'eth1_data'
    this.eth1Data.treeHashWith(h);

    // Field 'graffiti'
    this.graffiti.treeHashWith(h);

    // Field 'proposer_slashings'
    {
      const subIdx = h.index();
      for (const item of this.proposerSlashings) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.proposerSlashings.length, 16);
    }

    // Field 'attester_slashings'
    {
      const subIdx = h.index();
      for (const item of this.attesterSlashings) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.attesterSlashings.length, 2);
    }

    // Field 'attestations'
    {
      const subIdx = h.index();
      for (const item of this.attestations) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.attestations.length, 128);
    }

    // Field 'deposits'
    {
      const subIdx = h.index();
      for (const item of this.deposits) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.deposits.length, 16);
    }

    // Field 'voluntary_exits'
    {
      const subIdx = h.index();
      for (const item of this.voluntaryExits) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.voluntaryExits.length, 16);
    }

    // Field 'sync_aggregate'
    this.syncAggregate.treeHashWith(h);

    // Field 'execution_payload'
    this.executionPayload.treeHashWith(h);

    // Field 'bls_to_execution_changes'
    {
      const subIdx = h.index();
      for (const item of this.blsToExecutionChanges) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.blsToExecutionChanges.length, 16);
    }

    // Field 'blob_kzg_commitments'
    {
      const subIdx = h.index();
      for (const item of this.blobKzgCommitments) {
        item.treeHashWith(h);
      }
      h.merkleizeWithMixin(subIdx, this.blobKzgCommitments.length, 4096);
    }

    h.merkleize(idx);
  }
}

export class BeaconBlock {
  public slot: bigint = 0n;
  public proposerIndex: bigint = 0n;
  public parentRoot: Bytes32 = new Bytes32();
  public stateRoot: Bytes32 = new Bytes32();
  public body: BeaconBlockBody = new BeaconBlockBody();

  sszBytesLen(): number {
    let size = 84;
    size += this.body.sszBytesLen();
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Field 'slot'
    dv.setBigUint64(offset, this.slot, true); offset += 8;
    // Field 'proposer_index'
    dv.setBigUint64(offset, this.proposerIndex, true); offset += 8;
    // Field 'parent_root'
    offset = this.parentRoot.sszAppend(buf, offset);
    // Field 'state_root'
    offset = this.stateRoot.sszAppend(buf, offset);
    // Offset placeholder for 'body'
    const offsetPos0 = offset;
    offset += 4;

    // Dynamic field 'body'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    offset = this.body.sszAppend(buf, offset);
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): BeaconBlock {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 84) {
      throw new SszError('buffer too small');
    }
    const t = new BeaconBlock();
    t.slot = dv.getBigUint64(0, true);
    t.proposerIndex = dv.getBigUint64(8, true);
    t.parentRoot = Bytes32.fromSszBytes(buf.subarray(16, 48));
    t.stateRoot = Bytes32.fromSszBytes(buf.subarray(48, 80));
    const offset0 = dv.getUint32(80, true);
    if (offset0 !== 84) {
      throw new SszError('invalid offset');
    }

    {
      const dynBuf = buf.subarray(offset0, buf.length);
      t.body = BeaconBlockBody.fromSszBytes(dynBuf);
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'slot'
    h.putUint64(this.slot);

    // Field 'proposer_index'
    h.putUint64(this.proposerIndex);

    // Field 'parent_root'
    this.parentRoot.treeHashWith(h);

    // Field 'state_root'
    this.stateRoot.treeHashWith(h);

    // Field 'body'
    this.body.treeHashWith(h);

    h.merkleize(idx);
  }
}

export class SignedBeaconBlock {
  public message: BeaconBlock = new BeaconBlock();
  public signature: Bytes96 = new Bytes96();

  sszBytesLen(): number {
    let size = 100;
    size += this.message.sszBytesLen();
    return size;
  }

  sszAppend(buf: Uint8Array, offset: number): number {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    const startOffset = offset;

    // Offset placeholder for 'message'
    const offsetPos0 = offset;
    offset += 4;
    // Field 'signature'
    offset = this.signature.sszAppend(buf, offset);

    // Dynamic field 'message'
    dv.setUint32(offsetPos0, offset - startOffset, true);
    offset = this.message.sszAppend(buf, offset);
    return offset;
  }

  toSszBytes(): Uint8Array {
    const buf = new Uint8Array(this.sszBytesLen());
    this.sszAppend(buf, 0);
    return buf;
  }

  static fromSszBytes(buf: Uint8Array): SignedBeaconBlock {
    const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
    if (buf.length < 100) {
      throw new SszError('buffer too small');
    }
    const t = new SignedBeaconBlock();
    const offset0 = dv.getUint32(0, true);
    if (offset0 !== 100) {
      throw new SszError('invalid offset');
    }
    t.signature = Bytes96.fromSszBytes(buf.subarray(4, 100));

    {
      const dynBuf = buf.subarray(offset0, buf.length);
      t.message = BeaconBlock.fromSszBytes(dynBuf);
    }
    return t;
  }

  treeHashRoot(): Uint8Array {
    const h = HasherPool.get();
    try {
      this.treeHashWith(h);
      return h.hashRoot();
    } finally {
      HasherPool.put(h);
    }
  }

  treeHashWith(h: Hasher): void {
    const idx = h.index();

    // Field 'message'
    this.message.treeHashWith(h);

    // Field 'signature'
    this.signature.treeHashWith(h);

    h.merkleize(idx);
  }
}
